import { VOUCHER_FINAL_PROCESSING_LEVEL } from './voucherProcessingLevelDisplay';

export const DOCUMENT_ENTRY_LEVEL = '1';
export const DOCUMENT_PREPARED_LEVEL = '3';
export const DOCUMENT_APPROVED_LEVEL = '5';

/** Nhãn mức xử lý — giá thành (gt). */
export const COST_SHEET_LEVEL_LABELS: Record<string, string> = {
  '1': 'Nhập liệu',
  '3': 'Đã tính',
  '5': 'Đã duyệt',
  '9': 'Hoạch toán',
};

/** Nhãn mức xử lý — khấu hao TSCĐ (period run). */
export const DEPRECIATION_LEVEL_LABELS: Record<string, string> = {
  '3': 'Đã tạo bút toán nháp',
  '9': 'Hoạch toán',
};

export const COST_SHEET_LEVEL_FILTER_OPTIONS = [
  { value: '', label: 'Tất cả mức xử lý' },
  { value: '1', label: COST_SHEET_LEVEL_LABELS['1'] },
  { value: '3', label: COST_SHEET_LEVEL_LABELS['3'] },
  { value: '5', label: COST_SHEET_LEVEL_LABELS['5'] },
  { value: '9', label: COST_SHEET_LEVEL_LABELS['9'] },
];

export function formatCostSheetProcessingLevel(level: string | undefined | null): string {
  if (!level) return '—';
  return COST_SHEET_LEVEL_LABELS[level] ?? `Mức ${level}`;
}

export function formatDepreciationProcessingLevel(level: string | null | undefined): string {
  if (!level) return 'Chưa chạy';
  return DEPRECIATION_LEVEL_LABELS[level] ?? formatCostSheetProcessingLevel(level);
}

export function isFinalDocumentProcessingLevel(level: string | undefined | null): boolean {
  return String(level ?? '').trim() === VOUCHER_FINAL_PROCESSING_LEVEL;
}

/** TSCĐ master — tình trạng tài sản (không phải mức xử lý chứng từ). */
export const ASSET_LIFECYCLE_LABELS: Record<string, string> = {
  Active: 'Đang sử dụng',
  Disposed: 'Đã thanh lý',
  Suspended: 'Tạm dừng KH',
};

export function formatAssetLifecycle(lifecycle: string | undefined | null): string {
  if (!lifecycle) return '—';
  return ASSET_LIFECYCLE_LABELS[lifecycle] ?? lifecycle;
}
